                    <TimesheetRow
                        key={dayData.day}
                        dayData={dayData}
                        index={index}
                        onTimesheetChange={handleTimesheetChange}
                        isSiteInvalid={!!validationErrors[`site-${index}`]}
                        siteOptions={siteOptions}
